import { useEffect, useState } from "react";
import DashboardLayout from "../../components/layout/DashboardLayout";
import { getUsers, createEmployee, updateUser, deleteEmployee, blockUser } from "../../api/adminApi";
import ConfirmModal from "../../components/ConfirmModal";
import ErrorModal from "../../components/ErrorModal";

export default function UsersPage() {
  const [users, setUsers] = useState([]);
  const [filters, setFilters] = useState({ statusName: "" });
  const [formOpen, setFormOpen] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [modalAction, setModalAction] = useState("");
  const [errorModal, setErrorModal] = useState({ isOpen: false, message: "" });
  const [formData, setFormData] = useState({
    email: "", password: "", fullName: "", phone: "", roleName: "COURIER"
  });

  useEffect(() => {
    loadUsers();
  }, [filters]);

  const loadUsers = async () => {
    const data = await getUsers(filters);
    setUsers(data.content || []);
  };

  const openCreate = () => {
    setEditMode(false);
    setFormData({ email: "", password: "", fullName: "", phone: "", roleName: "COURIER" });
    setFormOpen(true);
  };

  const openEdit = (user) => {
    setEditMode(true);
    setSelectedUser(user);
    setFormData({
      email: user.email,
      fullName: user.fullName,
      phone: user.phone || "",
    });
    setFormOpen(true);
  };

  const handleSubmit = async () => {
    try {
      if (editMode) {
        await updateUser(selectedUser.id, formData);
      } else {
        await createEmployee(formData);
      }
      setFormOpen(false);
      loadUsers();
    } catch (e) {
      setErrorModal({ isOpen: true, message: e.message });
    }
  };

  const handleConfirm = async () => {
    if (!selectedUser) return;

    if (modalAction === "delete") {
      await deleteEmployee(selectedUser.id);
    } else {
      const isBlocked = selectedUser.status === "Заблокирован";
      await blockUser(selectedUser.id, !isBlocked);
    }

    setModalOpen(false);
    loadUsers();
  };

  return (
    <DashboardLayout>
      <div className="p-4">

        {/* FILTERS */}
        <div className="mb-4 flex gap-4 items-center">
          <select
            className="border rounded-lg px-3 py-2"
            onChange={(e) => setFilters({ ...filters, statusName: e.target.value })}
          >
            <option value="">Все статусы</option>
            <option value="Активен">Активен</option>
            <option value="Заблокирован">Заблокирован</option>
          </select>

          <button
            onClick={openCreate}
            className="ml-auto bg-indigo-500 hover:bg-indigo-600 text-white px-4 py-2 rounded-lg"
          >
            + Создать
          </button>
        </div>

        {/* TABLE */}
        <div className="bg-white rounded-2xl shadow-xl overflow-hidden">
          <table className="w-full">
            <thead className="bg-gradient-to-r from-indigo-500 to-purple-500 text-white">
              <tr>
                <th className="p-3">ID</th>
                <th>Email</th>
                <th>Имя</th>
                <th>Роль</th>
                <th>Статус</th>
                <th>Действия</th>
              </tr>
            </thead>
            <tbody>
              {users.map(u => (
                <tr key={u.id} className="text-center border-b hover:bg-gray-50">
                  <td className="p-3">{u.id}</td>
                  <td>{u.email}</td>
                  <td>{u.fullName}</td>
                  <td>{u.role}</td>
                  <td>
                    <span className={`px-3 py-1 rounded-full text-white text-sm ${u.status === "Активен" ? "bg-green-500" : "bg-red-500"}`}>
                      {u.status}
                    </span>
                  </td>
                  <td className="flex gap-2 justify-center py-2">
                    <button onClick={() => openEdit(u)} className="text-blue-500 hover:scale-125 transition-transform">✏️</button>
                    <button
                      onClick={() => {
                        setSelectedUser(u);
                        setModalAction("block");
                        setModalOpen(true);
                      }}
                      className="text-yellow-500 hover:scale-125 transition-transform"
                    >
                      ⛔
                    </button>
                    <button
                      onClick={() => {
                        if (u.role === "ADMIN") {
                          setErrorModal({ isOpen: true, message: "Нельзя удалить ADMIN" });
                        } else {
                          setSelectedUser(u);
                          setModalAction("delete");
                          setModalOpen(true);
                        }
                      }}
                      className="text-red-500 hover:scale-125 transition-transform"
                    >
                      🗑
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* FORM MODAL */}
        {formOpen && (
          <div className="fixed inset-0 bg-black bg-opacity-40 flex items-center justify-center z-50">
            <div className="bg-white rounded-2xl shadow-2xl p-6 w-96 flex flex-col gap-3">
              <h2 className="text-xl font-bold text-indigo-600">
                {editMode ? "Редактирование" : "Создание"}
              </h2>

              <input
                placeholder="Email"
                className="border rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-400"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
              />

              {!editMode && (
                <input
                  placeholder="Пароль"
                  type="password"
                  className="border rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-400"
                  value={formData.password}
                  onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                />
              )}

              <input
                placeholder="Имя"
                className="border rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-400"
                value={formData.fullName}
                onChange={(e) => setFormData({ ...formData, fullName: e.target.value })}
              />

              <input
                placeholder="Телефон"
                className="border rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-400"
                value={formData.phone}
                onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
              />

              {!editMode && (
                <select
                  className="border rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-400"
                  value={formData.roleName}
                  onChange={(e) => setFormData({ ...formData, roleName: e.target.value })}
                >
                  <option value="COURIER">COURIER</option>
                  <option value="LOGIST">LOGIST</option>
                </select>
              )}

              <div className="flex justify-end gap-2 mt-2">
                <button
                  onClick={() => setFormOpen(false)}
                  className="px-4 py-2 rounded-lg border hover:bg-gray-100"
                >
                  Отмена
                </button>
                <button
                  onClick={handleSubmit}
                  className="px-4 py-2 rounded-lg bg-indigo-500 hover:bg-indigo-600 text-white"
                >
                  Сохранить
                </button>
              </div>
            </div>
          </div>
        )}

        <ConfirmModal
          isOpen={modalOpen}
          title="Подтверждение"
          message="Вы уверены?"
          onConfirm={handleConfirm}
          onCancel={() => setModalOpen(false)}
        />

        <ErrorModal
          isOpen={errorModal.isOpen}
          title="Ошибка"
          message={errorModal.message}
          onClose={() => setErrorModal({ isOpen: false, message: "" })}
        />

      </div>
    </DashboardLayout>
  );
}
